const fs=require("fs"),csv=require("csv-parser");class CSVReader{constructor(filePath){this.filePath=filePath}async readWallets(){return new Promise(((resolve,reject)=>{const wallets=[];fs.createReadStream(this.filePath).pipe(csv()).on("data",(row=>{const rawAddress=(row.address||"").trim(),rawName=(row.name||"").trim();rawAddress&&!rawAddress.startsWith("#")&&this.validateAddress(rawAddress)&&rawName&&wallets.push({address:rawAddress.toLowerCase(),name:rawName})})).on("end",(()=>{console.log(`Loaded ${wallets.length} wallets from CSV`),resolve(wallets)})).on("error",(error=>{reject(error)}))}))}validateAddress(address){return/^0x[a-fA-F0-9]{40}$/.test(address)}}module.exports=CSVReader;